module.exports = a = async ({ params }) => {
  const email = params.email;
  if (!email || typeof email !== 'string' || email.trim() === '') {
    return false;
  }

  const match = email.match(/^[^@]+@(.+)$/);
  if (match && match[1]) {
    return { 'domain': match[1].toLowerCase() };
  }

  return false;
}

