/**
 * Checks if there is only one element and if so auto-submits.
 */
const autoClickOnSingleEntry = () => {
    const selectElement = document.getElementById('select');
    const btnContinue = document.getElementById('btnContinue');
    // Filter out the placeholder value
    if (selectElement){
        const realOptions = Array.from(selectElement.options).filter(opt => opt.value !== "");
        if (realOptions.length === 1 && btnContinue) {
            selectElement.value = realOptions[0].value;
            btnContinue.click();
        }   
    }
};

/**
 * Sets focus to the DOM element specified by its ID.
 * @param {string} id - The ID of the DOM element to focus.
 */
const setFieldFocus = (id) => {
    const element = document.getElementById(id);
    if (element) {
        element.focus();
    } else {
        console.log(`Element with ID ${id} not found.`);
    }
};

/**
 * Initializes the application by setting the focus to a specific field.
 */
const start = () => {
    setFieldFocus("select");
    if ({{autoSubmit}}) {
        autoClickOnSingleEntry();
    }
};

// Ensure the script runs after the DOM is fully loaded
if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", start);
} else {
    start();
}

