/**
 * Disclaimer:
 * This listing refers to a community-contributed integration that is maintained outside of the Ping Identity Marketplace, and is provided "as-is."
 * Ping Identity does not support this integration, or otherwise make any representation or warranty as to the functionality thereof.
 * Applicable licenses and/or restrictions may apply to the extent detailed at the relevant location where this integration is hosted.
 *
 * Overview:
 * Transforms an input array of objects into label/value pairs for use in UI components.
 * This is commonly used to render dropdown options in Handlebars templates.
 * The attribute names used for the label and value are provided dynamically via parameters.
 *
 * Example object array:
 * [
 *   { "abbr": "CA", "name": "California" },
 *   { "abbr": "NY", "name": "New York" },
 *   { "abbr": "TX", "name": "Texas" }
 * ]
 *
 * Example params:
 * {
 *   options: [...],
 *   optionLabelKey: "name",  // maps to the display label
 *   optionValueKey: "abbr"   // maps to the underlying value
 * }
 *
 * Result:
 * [
 *   { label: "California", value: "CA" },
 *   { label: "New York", value: "NY" },
 *   { label: "Texas", value: "TX" }
 * ]
 *
 * Author: se@pingidentity.com
 */
module.exports = async ({ params }) => {
	const { options, optionLabelKey, optionValueKey } = params;

	// Guard clause: ensure required inputs are present and valid
	if (
		!Array.isArray(options) ||
		!optionLabelKey ||
		!optionValueKey
	) {
		return { options: [] };
	}

	const formattedOptions = options.map((option) => {
		return {
			label: option[optionLabelKey],
			value: option[optionValueKey]
		};
	});

	return { options: formattedOptions };
};

